protected function findFiles(string $baseFolder): array
{
    /* Open the handle */
    $handle = @opendir($baseFolder);
    if ($handle === false) {
        return [];
    }

    $foundFiles = [];

    while (($file = readdir($handle)) !== false) {
        if ($file === '.' || $file === '..') {
            continue;
        }

        $itemPath = $baseFolder . DIRECTORY_SEPARATOR . $file;

        if (is_dir($itemPath)) {
            array_push($foundFiles, ...$this->findFiles($itemPath));
            continue;
        }

        if (! is_file($itemPath)) {
            continue;
        }

        $foundFiles[] = $itemPath;
    }

    /* Close the handle */
    closedir($handle);

    return $foundFiles;
}
